import{_ as t,o as r,c as a,ag as o}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"Configurer votre entreprise","description":"","frontmatter":{},"headers":[],"relativePath":"fr/getting-started/company-setup.md","filePath":"fr/getting-started/company-setup.md"}'),s={name:"fr/getting-started/company-setup.md"};function i(n,e,l,d,u,c){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="configurer-votre-entreprise" tabindex="-1">Configurer votre entreprise <a class="header-anchor" href="#configurer-votre-entreprise" aria-label="Permalink to &quot;Configurer votre entreprise&quot;">​</a></h1><p>Avant de pouvoir envoyer des factures, vous devez configurer les informations de votre entreprise. Ces donnees apparaissent sur vos factures, devis et autres documents.</p><h2 id="informations-de-l-entreprise" tabindex="-1">Informations de l&#39;entreprise <a class="header-anchor" href="#informations-de-l-entreprise" aria-label="Permalink to &quot;Informations de l&#39;entreprise&quot;">​</a></h2><p>Naviguez vers <strong>Entreprise</strong> dans la barre laterale pour acceder aux parametres de votre entreprise.</p><h3 id="champs-obligatoires" tabindex="-1">Champs obligatoires <a class="header-anchor" href="#champs-obligatoires" aria-label="Permalink to &quot;Champs obligatoires&quot;">​</a></h3><p>Ces champs sont necessaires pour envoyer des factures :</p><ul><li><strong>Nom de l&#39;entreprise</strong> -- Le nom enregistre de votre entreprise</li><li><strong>Adresse</strong> -- Rue, code postal et ville (l&#39;autocompletion d&#39;adresse est disponible)</li><li><strong>E-mail</strong> -- L&#39;adresse e-mail de contact de votre entreprise</li></ul><h3 id="champs-recommandes" tabindex="-1">Champs recommandes <a class="header-anchor" href="#champs-recommandes" aria-label="Permalink to &quot;Champs recommandes&quot;">​</a></h3><p>Ceux-ci sont fortement recommandes pour des factures professionnelles et la conformite legale :</p><ul><li><strong>Numero de TVA</strong> -- Votre numero d&#39;identification TVA (par ex., NL123456789B01)</li><li><strong>Chambre de Commerce / Numero d&#39;immatriculation</strong> -- Votre identifiant d&#39;immatriculation commerciale</li><li><strong>IBAN</strong> -- Votre numero de compte bancaire ou les clients doivent effectuer les paiements</li><li><strong>Numero de telephone</strong> -- Telephone professionnel de contact</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Dans de nombreux pays, le numero de TVA et le numero d&#39;immatriculation sont legalement requis sur les factures. Assurez-vous qu&#39;ils sont remplis avant d&#39;envoyer votre premiere facture.</p></div><h2 id="image-de-marque" tabindex="-1">Image de marque <a class="header-anchor" href="#image-de-marque" aria-label="Permalink to &quot;Image de marque&quot;">​</a></h2><h3 id="logo-de-l-entreprise" tabindex="-1">Logo de l&#39;entreprise <a class="header-anchor" href="#logo-de-l-entreprise" aria-label="Permalink to &quot;Logo de l&#39;entreprise&quot;">​</a></h3><p>Telechargez le logo de votre entreprise pour qu&#39;il apparaisse sur :</p><ul><li>Les factures et devis (PDF)</li><li>Les communications par e-mail</li><li>Votre page publique d&#39;entreprise</li><li>Le portail de paiement client</li></ul><p>Formats acceptes : PNG, JPG, SVG. Pour de meilleurs resultats, utilisez une image haute resolution avec un fond transparent.</p><h3 id="palette-de-couleurs" tabindex="-1">Palette de couleurs <a class="header-anchor" href="#palette-de-couleurs" aria-label="Permalink to &quot;Palette de couleurs&quot;">​</a></h3><p>Personnalisez la couleur d&#39;accentuation utilisee sur vos factures et documents pour correspondre a l&#39;identite de votre marque.</p><h2 id="parametres-financiers-par-defaut" tabindex="-1">Parametres financiers par defaut <a class="header-anchor" href="#parametres-financiers-par-defaut" aria-label="Permalink to &quot;Parametres financiers par defaut&quot;">​</a></h2><p>Configurez les valeurs par defaut qui s&#39;appliquent aux nouvelles factures et aux nouveaux devis :</p><ul><li><strong>Devise</strong> -- Votre devise par defaut (EUR par defaut)</li><li><strong>Conditions de paiement</strong> -- Nombre de jours par defaut avant l&#39;echeance d&#39;une facture (par ex., 14 ou 30 jours)</li><li><strong>Numerotation des factures</strong> -- Personnalisez le format de vos numeros de facture <ul><li>Prefixe (par ex., <code>INV-</code> ou <code>2024-</code>)</li><li>Numero de depart</li><li>Incrementation automatique</li></ul></li></ul><h3 id="exemples-de-numerotation-de-factures" tabindex="-1">Exemples de numerotation de factures <a class="header-anchor" href="#exemples-de-numerotation-de-factures" aria-label="Permalink to &quot;Exemples de numerotation de factures&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Format</th><th>Exemple</th></tr></thead><tbody><tr><td>Simple</td><td><code>001</code>, <code>002</code>, <code>003</code></td></tr><tr><td>Avec prefixe</td><td><code>INV-001</code>, <code>INV-002</code></td></tr><tr><td>Base sur l&#39;annee</td><td><code>2024-001</code>, <code>2024-002</code></td></tr></tbody></table><p>Les options de reinitialisation de la numerotation et le format peuvent etre ajustes a tout moment. Les numeros de factures existants ne sont jamais modifies.</p><h2 id="modele-pdf" tabindex="-1">Modele PDF <a class="header-anchor" href="#modele-pdf" aria-label="Permalink to &quot;Modele PDF&quot;">​</a></h2><p>MyCompanyDesk genere automatiquement des factures PDF professionnelles. Vous pouvez personnaliser la mise en page a l&#39;aide de l&#39;<strong>editeur PDF</strong> :</p><ul><li>Ajuster la position et la visibilite des champs</li><li>Choisir les informations a afficher</li><li>Personnaliser les polices et les tailles</li><li>Previsualiser les modifications en temps reel avec une facture exemple</li></ul><p>Accedez a l&#39;editeur PDF depuis <strong>Entreprise &gt; Editeur PDF</strong> ou depuis la section image de marque.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>La personnalisation avancee du PDF necessite le plan <strong>Pro</strong> ou superieur.</p></div><h2 id="activation-des-fonctionnalites" tabindex="-1">Activation des fonctionnalites <a class="header-anchor" href="#activation-des-fonctionnalites" aria-label="Permalink to &quot;Activation des fonctionnalites&quot;">​</a></h2><p>MyCompanyDesk dispose de modules optionnels que vous pouvez activer ou desactiver selon vos besoins professionnels :</p><ul><li><strong>Objets / Actifs</strong> -- Pour la gestion de biens locatifs et d&#39;actifs</li><li><strong>Contrats</strong> -- Pour les contrats de services ou de location recurrents</li><li><strong>Projets</strong> -- Pour le travail base sur des projets et le suivi du temps</li><li><strong>Devis</strong> -- Pour l&#39;envoi de devis</li><li><strong>Autoliquidation</strong> -- Pour les transactions B2B intra-UE</li><li><strong>Suggestions IA</strong> -- Pour la categorisation et les recommandations intelligentes</li><li><strong>Numerisation de recus</strong> -- Pour la saisie de depenses basee sur l&#39;OCR</li><li><strong>Verification de texte</strong> -- Pour la grammaire et l&#39;orthographe de vos documents</li></ul><p>La desactivation d&#39;un module le masque dans la navigation, gardant votre espace de travail epure et concentre.</p><h2 id="prochaines-etapes" tabindex="-1">Prochaines etapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines etapes&quot;">​</a></h2><p>Votre entreprise est configuree. Il est temps de <a href="/fr/getting-started/first-invoice">creer votre premiere facture</a>.</p>',35)])])}const f=t(s,[["render",i]]);export{m as __pageData,f as default};
